// Use G1GC with 200ms pause target
java -XX:+UseG1GC -XX:MaxGCPauseMillis=200 -Xmx4g MyApp

// Use ZGC for ultra-low latency
java -XX:+UseZGC -Xmx16g MyApp

// GC Logging (Java 9+)
java -Xlog:gc*:file=gc.log:time,level,tags -jar app.jar

// Common tuning flags
-Xms4g          // initial heap size
-Xmx4g          // max heap size (set equal to Xms to avoid resizing)
-XX:NewRatio=2  // Old:Young ratio (2:1)
-XX:SurvivorRatio=8  // Eden:Survivor ratio
-XX:MaxMetaspaceSize=256m  // cap metaspace growth

// View JIT compilation activity
java -XX:+PrintCompilation -jar app.jar

// Control compilation thresholds
-XX:CompileThreshold=10000  // invocations before C2 compiles

// Print inlining decisions
-XX:+UnlockDiagnosticVMOptions -XX:+PrintInlining

// Code cache sizing
-XX:ReservedCodeCacheSize=512m  // increase if code cache fills

// Disable tiered compilation (force C2 from start — slower startup)
-XX:-TieredCompilation

// GraalVM JIT (alternative)
-XX:+UnlockExperimentalVMOptions -XX:+UseJVMCICompiler

// This object does NOT escape — JIT can stack-allocate or scalar-replace
public double distance(double x1, double y1, double x2, double y2) {
    Point p = new Point(x2 - x1, y2 - y1); // NoEscape!
    return Math.sqrt(p.x * p.x + p.y * p.y);
    // After scalar replacement: no Point object created!
    // Equivalent to: return Math.sqrt(dx*dx + dy*dy);
}

// This object DOES escape — must be heap-allocated
public Point createPoint(double x, double y) {
    return new Point(x, y); // GlobalEscape — returned to caller
}

// Lock elision — synchronized removed for non-escaping objects
public String format(int value) {
    StringBuffer sb = new StringBuffer(); // NoEscape
    sb.append("Value: ").append(value);
    return sb.toString();
    // JIT removes StringBuffer's sync because sb doesn't escape!
}

// Verify escape analysis decisions:
// java -XX:+UnlockDiagnosticVMOptions -XX:+PrintEscapeAnalysis MyApp

